function ModelGuildMelee:OnMatchedGroupResp(pb)
    local pbItem = nil
    for _,v in ipairs(pb.typeData) do
        if v.type == 102 then
            pbItem = v
            break
        end
    end
    if not pbItem then
        return
    end
    self._servers = {}
    self._groupReportUrl = pbItem.reportUrl
    for i, v in ipairs(pbItem.servers) do
        local info = StructServer:New()
        info:CreateByPb(v)
        table.insert(self._servers,info)
    end
    self._guildBattleGroupId = pbItem.guildBattleGroupId
end
--联盟混战状态通知 （非主动请求时下发，登录、变更）
function ModelGuildMelee:OnGuildMeleeStateResp(pb)
    if not gModelFunctionOpen:CheckIsOpened(12106000) then
        return
    end
    local state = pb.state or 0                     --联盟混战状态 （1.未开启状态（未开启当天无盟战），2.预备状态(未开启当天有盟战)
    --3.报名状态（报名阶段） 4.准备状态（准备阶段） 5.混战状态(混战阶段)）6.结束状态
    local startTime = pb.startTime                  --进入下一状态时间点（时刻）
    local firstOpen = pb.firstOpen                  --（下次）是否首次开启 0否 1是
    local signUpGuildCount = pb.signUpGuildCount    --全服报名联盟数
    local remainGuildCount = pb.remainGuildCount    --剩余联盟数 (未被淘汰联盟数)
    local signUpPlayerState = pb.signUpPlayerState  --玩家报名状态 0未报名 1已报名

    self._meleeInfo = {
        state = state,
        startTime = startTime,
        firstOpen = firstOpen,
        signUpGuildCount = signUpGuildCount,
        remainGuildCount = remainGuildCount,
        signUpPlayerState = signUpPlayerState,
    }

    ---刷新主界面玩法提示
    gModelGeneral:GetSetNoticeListItem(ModelGeneral.NOTICE_MELEE, tonumber(startTime)/1000, state)


    local oldState = self._oldState or 0

    if not self._oldState and state == ModelGuildMelee.STATE_APPLY and signUpPlayerState == 0 then
        local isAlert = gModelGeneral:FindAlertId(100103)
        if not isAlert then
            local items = gModelGuild:GetGuildConfigRefByKey("battleShowReward")
            local itemList = LxDataHelper.ParseItem(items)
            local t = {refId = 100103,itemList = itemList,func = function (...)
                local functionId = gLGameLanguage:IsForeignRegion() and 12100002 or 12100001
                if gModelGuild:GetBHaveGuild() then
                    functionId = 12106100
                end
                gModelFunctionOpen:Jump(functionId)
            end }
            gModelGeneral:InsertPopWndPara(t)
            gModelGeneral:OpenPopWnd()
        end
    end
    if(oldState < state) then
        if state == ModelGuildMelee.STATE_READY then
            self:ClearMeleeSignUpInfo()
            self._reportList = {}
        elseif state == ModelGuildMelee.STATE_APPLY then
            self:ClearMeleeSignUpInfo()
            self._reportList = {}
            local wnd = GF.FindFirstWndByName("UIGdWar2Win")
            if wnd then
                FireEvent(EventNames.ON_GUILD_BATTLE,2)
            else
                wnd = GF.FindFirstWndByName("UIGdWin")
                if wnd then
                    FireEvent(EventNames.ON_GUILD_BATTLE,1)
                end
            end
        elseif state == ModelGuildMelee.STATE_Melee then

            if signUpGuildCount >= GameTable.ClanConfigRef["battleStartCondition"] then
                local items = gModelGuild:GetGuildConfigRefByKey("battleShowReward")
                local itemList = LxDataHelper.ParseItem(items)
                local t = {refId = 100104,itemList = itemList,func = function (...)
                    local functionId = gLGameLanguage:IsForeignRegion() and 12100002 or 12100001
                    if gModelGuild:GetBHaveGuild() then
                        functionId = 12106200
                    end
                    gModelFunctionOpen:Jump(functionId)
                end }
                gModelGeneral:InsertPopWndPara(t)
                gModelGeneral:OpenPopWnd()
            end
        end
    end
    self._oldState = state
end

