--联盟混战 全服战报列表响应
function ModelGuildMelee:OnGuildMeleeReportInfoListResp(pb)
    local lists = pb.list                   --战报列表
    local _type = pb.type                   --1向前size条 2向后size条
    self._logDownType = _type
    local list = {}
    local _continuousWinList = self._continuousWinList or {}

    local battleWinStreak = gModelGuild:GetGuildConfigRefByKey("battleWinStreak")
    for i, v in ipairs(lists) do
        local info = StructGuildMeleeReportInfo:New()
        info:CreateByPb(v)
        table.insert(list,info)
        if _type == 2 then
            if info.winCount >= battleWinStreak then
                table.insert(_continuousWinList,info)
            end
        end
    end

    self._continuousWinList = _continuousWinList
    local showTime = gModelGuild:GetGuildConfigRefByKey("battleReportShowTime")
    if (self._isReport ~= 3 or self._req or self._logDownType == 1) or (not showTime or showTime <=0) then
        self._req = false
        self:SetReportList(list)
    else
        for i, v in ipairs(list) do
            table.insert(self._stockpileReportList,v)
        end
        table.sort(self._stockpileReportList,function (a,b)
            return  a.seq < b.seq
        end)
        if #self._stockpileReportList > 0 then
            self._timer:TimerRemoveByKey(self._reportKey)
            self:OnCountDown(self._reportKey)
            self._timer:TimerCreate(self._reportKey, function(...) self:OnCountDown(...) end, showTime/1000, false, -1)
        end
    end
    if self._isReport == 2 then
        self._isReport = 3
    end
end

function ModelGuildMelee:OnCountDown(key)
    if key == self._reportKey then
        local info = nil
        local inder = 1
        if self._logDownType == 1 then
            inder = #self._stockpileReportList
        end
        info =  self._stockpileReportList[inder]
        if not info then
            self._timer:TimerRemoveByKey(self._reportKey)
            return
        end
        self:SetReportList({info})
        table.remove(self._stockpileReportList,inder)
    end
end

