function ModelGuildMelee:OnGuildMeleeEndTopInfoResp(pb)
    local slist = pb.list                           --战果弹窗信息
    local integralRank = pb.integralRank            --最近积分排名
    local bestIntegralRank = pb.bestIntegralRank    --最佳积分排名
    local winCount = pb.winCount                    --最近胜数
    local loseCount = pb.loseCount                  --最近败数
    local integral = pb.integral                    --最近积分数值
    local list = {}
    for i, v in ipairs(slist) do
        local info = StructGuildMeleeEndTopInfo:New()
        info:CreateByPb(v)
        table.insert(list,info)
    end
    table.sort(list,function (a,b)
        return a.rank < b.rank
    end)
    local data = {
        integralRank = integralRank,
        bestIntegralRank = bestIntegralRank,
        winCount = winCount,
        loseCount = loseCount,
        integral = integral,
    }
    GF.OpenWndTop("UIGdMeleeResult",{resultList = list,data = data})
end

