function ModelGuildMelee:GetIsChangeEmbattle()
    local _meleeInfo = self:GetGuildMeleeInfo()
    if not _meleeInfo then
        return false
    end
    if _meleeInfo.state == ModelGuildMelee.STATE_PREPARE or _meleeInfo.state == ModelGuildMelee.STATE_Melee then
        return false
    end
    return true
end

