function ModelGuildMelee:GetContinuousWin()
    local item = self._continuousWinList and self._continuousWinList[1]
    if not item then
        return nil
    end
    local _continuousWinList = table.clone(item)
    table.remove(self._continuousWinList, 1)
    return _continuousWinList
end

function ModelGuildMelee:GetIsMayQuitGuild(isTips)
    local _meleeInfo = self:GetGuildMeleeInfo()
    if not _meleeInfo then
        return true
    end
    if (_meleeInfo.state == ModelGuildMelee.STATE_APPLY or _meleeInfo.state == ModelGuildMelee.STATE_PREPARE or _meleeInfo.state == ModelGuildMelee.STATE_Melee) and _meleeInfo.signUpPlayerState == 1 then
        if isTips then
            GF.ShowMessage(ccClientText(17961))
        end
        return false
    end
    return true
end

function ModelGuildMelee:SetSignUpListByType(type,list)
    if not self._signUpList then
        self._signUpList = {}
    end
    self._signUpList[type] = list
end
--
function ModelGuildMelee:DelSignUpListByType(type,seq)
    local list = self._signUpList[type]
    if not list then
        return
    end
    list[seq] = nil
end

function ModelGuildMelee:GetSignUpListByType(type,isSort)--获取报名列表
    if not self._signUpList then
        return {}
    end
    local slist = self._signUpList[type] or {}
    if(not isSort)then
        return slist
    end
    local list = {}
    for i, v in pairs(slist) do
        table.insert(list,v)
    end
    table.sort(list,function (a,b)
        if a.seq ~= b.seq then
            return a.seq < b.seq
        end
        return false
    end)
    if not self._isSignUp and #list then
        self._isSignUp = true
        self:OnGuildMeleeSignUpInfoListTestReq()
        self:OnGuildMeleeMemberSignUpInfoListReq()
    end
    return list
end

function ModelGuildMelee:SetReportListByType(type,list)
    self._reportList[type] = list
end

function ModelGuildMelee:GetReportListByType(type,isSort)--获取战报列表
    if not self._reportList then
        self._reportList = {}
    end
    local slist = self._reportList[type] or {}
    if(not isSort)then
        return slist
    end
    local list = {}
    for i, v in pairs(slist) do
        table.insert(list,v)
    end

    table.sort(list,function (a,b)
        return a.seq < b.seq
    end)
    local gList = {}
    local round = 0
    for i, v in ipairs(list) do
        if round == 0 then
            round = v.round
        end
        if(#gList == 0)then
            table.insert(gList,{type = 1,round = round,seq = v.seq})
        elseif(round ~= 0 and round ~= v.round)then
            round = v.round
            table.insert(gList,{type = 1,round = round,seq = v.seq})
        end
        v.type = 2
        table.insert(gList,v)
        if(v.oust > 0)then
            local log = table.light_copy(v)
            log.type = 3
            if type ~= ModelGuildMelee.REPORT_MINE then
                table.insert(gList,log)
            end
            if v.oust == 2 then
                local slog = table.light_copy(v)
                slog.type = 4
                table.insert(gList,slog)
            end
        end
        round = v.round
    end
    self:OnClickReportReq()
    return gList
end

function ModelGuildMelee:OnClickReportReq()
    if self._isReport == 1 then
        self._isReport = 2
        self:OnGuildMeleeReportInfoListReq()
        self:OnGuildMeleeGuildReportInfoListReq()
        self:OnGuildMeleeMyReportInfoListReq()
    end
end

function ModelGuildMelee:GetGroupReportUrl()
    return self._groupReportUrl
end

function ModelGuildMelee:GetServerReportUrl(serverId)
    local bool = self:GetIsGrouping()
    if not bool then
        return gLGameLogin:GetHttpReportUrl()
    end
    local list = self:GetServers()
    for k,v in ipairs(list) do
        if v.serverId == serverId then
            return v.reportUrl
        end
    end

    return self:GetGroupReportUrl()
end

function ModelGuildMelee:SetReportList(list)
    local _wlist = self:GetReportListByType(ModelGuildMelee.REPORT_WORLD,false)
    local _glist = self:GetReportListByType(ModelGuildMelee.REPORT_GUILD,false)
    local _mlist = self:GetReportListByType(ModelGuildMelee.REPORT_MINE,false)
    for i, v in ipairs(list) do
        _wlist[v.seq] = v
        local guildId = gModelPlayer:GetGuildId()
        if v.guildIdA == guildId or v.guildIdB == guildId then
            _glist[v.seq] = v
        end
        local playerId = gModelPlayer:GetPlayerId()
        if v.playerIdA == playerId or v.playerIdB == playerId then
            _mlist[v.seq] = v
        end
    end
    self:SetReportListByType(ModelGuildMelee.REPORT_WORLD,_wlist)
    self:SetReportListByType(ModelGuildMelee.REPORT_GUILD,_glist)
    self:SetReportListByType(ModelGuildMelee.REPORT_MINE,_mlist)
    FireEvent(EventNames.ON_GUILD_MELEE_REPORT)
end

