----------------------------获取表数据--------------------------------------
function ModelGuildMelee:GetGuildBattleRewardRefByType(type)--排行奖励表
    local bool = self:GetIsGrouping()
    if bool then
        if type == 1 then
            type = 3
        else
            type = 4
        end
    end
    local list = {}
    for i, v in pairs(GameTable.ClanWarRewardRef) do
        if(type == v.type)then
            local rewardStr = v.reward
            local titleRewardStr = v.titleReward
            if not string.isempty(titleRewardStr) then
                rewardStr = titleRewardStr..','..rewardStr
            end
            local items = LxDataHelper.ParseItem(rewardStr)
            local data = {
                refId = v.refId,
                type  = v.type,
                sort = v.sort,
                rank = v.rank,
                reward = items,
            }

            table.insert(list,data)
        end
    end
    table.sort(list , function (a,b)
        return a.sort < b.sort
    end)
    return list
end

function ModelGuildMelee:GetIsBoolApply()
    local _meleeInfo = self:GetGuildMeleeInfo()
    local state = _meleeInfo.state
    if state < ModelGuildMelee.STATE_APPLY then
        GF.ShowMessage(ccClientText(17946))
        return false
    elseif state > ModelGuildMelee.STATE_APPLY then
        GF.ShowMessage(ccClientText(17947))
        return false
    end
    local ginfo = gModelGuild:GetSelfGuildInfo()
    if not ginfo then
        return false
    end
    local enterTime = tonumber(ginfo.enterTime)/1000
    local time = GetTimestamp()
    local timespan = time - enterTime
    local condition = gModelGuild:GetGuildConfigRefByKey("battlePartakeCondition")
    if condition > 0 then
        if timespan < condition * 60 * 60 then
            GF.ShowMessage(string.replace(ccClientText(17948),condition))
            return false
        end
    end
    return true
end

function ModelGuildMelee:IsInApplyState()
    local meleeInfo = self:GetGuildMeleeInfo()
    if not meleeInfo then
        return
    end
    local state = meleeInfo.state
    return state == ModelGuildMelee.STATE_APPLY
end

function ModelGuildMelee:DelayEffectWnd(func)
    self._effectWndCall = func
end

function ModelGuildMelee:GetEffectWndCall()
    local call = self._effectWndCall
    self._effectWndCall = nil
    return call
end

function ModelGuildMelee:GetGuildBattleBuffRefByRefId(refId)
    return GameTable.ClanWarBuffRef[refId]
end
